const body = $json.body || $json;
const meetingId = body.meetingId || 'unknown';
const topic = body.topic || 'Team Meeting';
const agents = body.agents || [];
const summary = body.summary || '';
const transcript = body.transcript || [];
const createdAt = body.createdAt || new Date().toISOString();
const endedAt = body.endedAt || new Date().toISOString();
const duration = body.duration || 0;
const messageCount = body.messageCount || 0;
const telegram = body.telegram || null;
const confluenceSpace = body.confluenceSpace || 'CE';
const confluenceParentPage = body.confluenceParentPage || 'Meetings';
const jiraProject = body.jiraProject || 'CER';
const runnerUrl = body.runnerUrl || '{{RUNNER_INTERNAL_URL}}';

// Format date for page title
const d = new Date(createdAt);
const dateStr = d.toISOString().split('T')[0];
const timeStr = d.toTimeString().split(' ')[0].substring(0, 5);
const shortId = meetingId.substring(0, 8);
const pageTitle = `Meeting - ${dateStr} ${timeStr} - [${shortId}] ${topic.substring(0, 50)}`;

// Build Confluence page body (ADF-like HTML)
let pageBody = `<h1>Meeting Minutes</h1>`;
pageBody += `<p><strong>Date:</strong> ${d.toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} at ${timeStr}</p>`;
pageBody += `<p><strong>Topic:</strong> ${topic}</p>`;
pageBody += `<p><strong>Participants:</strong> ${agents.join(', ')}</p>`;
pageBody += `<p><strong>Duration:</strong> ${Math.round(duration / 60)} minutes | <strong>Messages:</strong> ${messageCount}</p>`;
pageBody += `<p><strong>Meeting ID:</strong> ${meetingId}</p>`;
pageBody += `<hr/>`;

// Summary / Outcomes
pageBody += `<h2>Outcomes</h2>`;
const summaryHtml = summary
  .replace(/## (.+)/g, '<h3>$1</h3>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/^- \[ \] (.+)$/gm, '<li>$1</li>')
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/\n/g, '<br/>');
pageBody += summaryHtml;

// Full transcript
pageBody += `<h2>Full Transcript</h2>`;
for (const msg of transcript) {
  const speaker = msg.agent || msg.name || 'unknown';
  const content = (msg.content || '').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br/>');
  pageBody += `<h4>${speaker}</h4><p>${content}</p><hr/>`;
}

// Parse action items from summary
const actionItems = [];
const actionRegex = /- \[ \] (.+?)\s*[\u2014\u2013-]\s*Owner:\s*(\S+)\s*[\u2014\u2013-]\s*Priority:\s*(High|Medium|Low)/gi;
let match;
while ((match = actionRegex.exec(summary)) !== null) {
  actionItems.push({
    task: match[1].trim(),
    owner: match[2].trim(),
    priority: match[3].trim()
  });
}

// Also try simpler patterns
if (actionItems.length === 0) {
  const simpleRegex = /- \[ \] (.+?)\s*[\u2014\u2013-]\s*(?:Owner:?\s*)?(\S+)/gi;
  while ((match = simpleRegex.exec(summary)) !== null) {
    actionItems.push({
      task: match[1].trim(),
      owner: match[2].trim(),
      priority: 'Medium'
    });
  }
}

// Determine highest priority for parent story
const priorityOrder = { 'High': 0, 'Medium': 1, 'Low': 2 };
let highestPriority = 'Medium';
for (const item of actionItems) {
  if ((priorityOrder[item.priority] || 1) < (priorityOrder[highestPriority] || 1)) {
    highestPriority = item.priority;
  }
}
const priorityMap = { 'High': '2', 'Medium': '3', 'Low': '4' };

return [{ json: {
  meetingId,
  topic,
  agents,
  summary,
  transcript,
  createdAt,
  endedAt,
  duration,
  messageCount,
  telegram,
  confluenceSpace,
  confluenceParentPage,
  jiraProject,
  runnerUrl,
  pageTitle,
  pageBody,
  actionItems,
  dateStr,
  timeStr,
  highestPriority,
  parentPriorityId: priorityMap[highestPriority] || '3'
} }];

