// Split action items into individual subtasks with parent key
const data = $('Parse Outcomes').first().json;
const parentKey = $('Create Parent Story').first().json.key;
const actionItems = data.actionItems || [];
const jiraProject = data.jiraProject || 'CER';
const meetingId = data.meetingId;
const topic = data.topic;
const runnerUrl = data.runnerUrl;

const ownerToLabel = {
  'product-manager': 'agent:pm',
  'engineer-planner': 'agent:planner',
  'engineer-implementer': 'agent:implementer',
  'engineer-reviewer': 'agent:reviewer',
  'architect': 'agent:architect',
  'security-agent': 'agent:security',
  'qa-agent': 'agent:qa',
  'ux-agent': 'agent:ux',
  'marketing': 'agent:marketing',
  'sales-development': 'agent:sales-dev',
  'ui-engineer': 'agent:ui',
  'ba-agent': 'agent:ba',
  'ask-dave-agent': 'agent:troubleshoot',
  'uat-agent': 'agent:uat',
};

const priorityMap = { 'High': '2', 'Medium': '3', 'Low': '4' };

const items = actionItems.map((item, idx) => {
  let owner = item.owner || '';
  if (owner.includes(':')) {
    owner = owner.split(':').pop();
  }
  const fullTask = item.task || '';
  const shortTask = fullTask.length > 220 ? fullTask.substring(0, 217) + '...' : fullTask;

  return {
    idx,
    task: fullTask,
    shortTask,
    owner,
    priority: item.priority,
    jiraProject,
    meetingId,
    topic,
    runnerUrl,
    parentKey,
    agentLabel: ownerToLabel[owner] || null,
    jiraPriorityId: priorityMap[item.priority] || '3',
    labels: ownerToLabel[owner] ? [ownerToLabel[owner], 'meeting-action'] : ['meeting-action']
  };
});

return items.map(i => ({ json: i }));

const transitions = $json.transitions || [];
const inProgress = transitions.find(t => 
  t.name.toLowerCase() === 'in progress' ||
  t.name.toLowerCase() === 'in-progress' ||
  t.name.toLowerCase().includes('progress')
);

if (!inProgress) {
  // No In Progress transition available — skip
  return [];
}

return [{ json: {
  transitionId: inProgress.id,
  issueKey: $('Create Parent Story').first().json.key
} }];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
